"use client";

import { JsonTreeView as ArkJsonTreeView } from "@ark-ui/react/json-tree-view";
import { ChevronRightIcon } from "lucide-react";
import type React from "react";
import { cn } from "@/lib/utils";

export const JsonTreeView = (
  props: React.ComponentProps<typeof ArkJsonTreeView.Root>
) => {
  const { lazyMount = true, unmountOnExit = true, className, ...rest } = props;

  return (
    <ArkJsonTreeView.Root
      className={cn(
        "json-tree-view w-full font-mono text-foreground [font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace]",
        "[&_[data-part=branch-content]]:relative",
        "[&_[data-part=branch-indent-guide]]:absolute [&_[data-part=branch-indent-guide]]:left-[calc((var(--depth)-1)*1rem)] [&_[data-part=branch-indent-guide]]:h-full [&_[data-part=branch-indent-guide]]:w-px [&_[data-part=branch-indent-guide]]:bg-border",
        "[&_[data-part=branch-control]]:flex [&_[data-part=branch-control]]:select-none [&_[data-part=branch-control]]:pl-[calc((var(--depth)-1)*0.75rem)]",
        "[&_[data-part=branch-control]:hover]:bg-muted",
        "[&_[data-part=branch-indicator][data-state=open]]:rotate-90 [&_[data-part=branch-indicator]]:mr-1 [&_[data-part=branch-indicator]]:inline-flex [&_[data-part=branch-indicator]]:origin-center [&_[data-part=branch-indicator]]:items-center [&_[data-part=branch-indicator]]:justify-center",
        "[&_[data-part=item]]:relative [&_[data-part=item]]:flex [&_[data-part=item]]:pl-[calc(((var(--depth)-1)*0.75rem)+0.75rem)]",
        "[&_[data-part=item]:hover]:bg-muted",
        "[&_[data-part=branch-text]]:flex [&_[data-part=branch-text]]:items-baseline [&_[data-part=item-text]]:flex [&_[data-part=item-text]]:items-baseline",
        className
      )}
      lazyMount={lazyMount}
      unmountOnExit={unmountOnExit}
      {...rest}
    />
  );
};

export const JsonTreeViewTree = (
  props: React.ComponentProps<typeof ArkJsonTreeView.Tree>
) => {
  const { arrow, ...rest } = props;
  return (
    <ArkJsonTreeView.Tree
      arrow={arrow ?? <ChevronRightIcon />}
      className={cn(
        "flex flex-col font-mono text-muted-foreground text-xs leading-7 [font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace] [&_svg]:size-4",
        "[&_[data-type=string]]:text-green-600 dark:[&_[data-type=string]]:text-green-400",
        "[&_[data-type=number]]:text-blue-600 dark:[&_[data-type=number]]:text-blue-400",
        "[&_[data-type=boolean]]:font-semibold [&_[data-type=boolean]]:text-amber-600 dark:[&_[data-type=boolean]]:text-amber-400",
        "[&_[data-type=null]]:font-semibold [&_[data-type=null]]:text-muted-foreground [&_[data-type=null]]:italic",
        "[&_[data-kind=key]]:font-medium [&_[data-kind=key]]:text-foreground",
        "[&_[data-kind=colon]]:mx-1 [&_[data-kind=colon]]:text-muted-foreground",
        rest.className
      )}
      {...rest}
    />
  );
};
